files.css:
body { margin: 0; font-family: system-ui, sans-serif; color: #1e293b; line-height: 1.5; }
.site-header { display: flex; flex-wrap: wrap; align-items: center; justify-content: space-between; gap: 0.75rem; padding: 0.75rem 1rem; background: #2563eb; color: #fff; }
.brand { font-weight: 700; font-size: 1.1rem; }
.topnav { display: flex; gap: 1rem; }
.topnav a { color: #dbeafe; text-decoration: none; }
.layout { display: grid; grid-template-columns: 170px 1fr; min-height: 220px; }
.sidebar { background: #dbeafe; padding: 1rem; }
.sidebar a { display: block; color: #1e40af; text-decoration: none; margin-bottom: 0.5rem; }
main { padding: 1.25rem; }
main h1 { margin-top: 0; color: #2563eb; font-size: 1.35rem; }
.card { background: #f8fafc; border: 1px solid #dbeafe; border-radius: 8px; padding: 1rem; margin-top: 1rem; }
.card h2 { margin: 0 0 0.35rem; font-size: 1rem; }
.site-footer { background: #f1f5f9; color: #64748b; padding: 0.75rem 1rem; font-size: 0.85rem; border-top: 1px solid #dbeafe; }
@media (max-width: 560px) {
  .layout { grid-template-columns: 1fr; }
  .sidebar { display: flex; flex-wrap: wrap; gap: 0.75rem; }
  .sidebar a { margin-bottom: 0; }
}

body { margin: 0; font-family: system-ui, sans-serif; color: #1e293b; }
.site-header { display: flex; flex-wrap: wrap; align-items: center; gap: 0.75rem; padding: 0.75rem 1rem; background: #1e293b; color: #fff; }
.menu-btn { padding: 0.35rem 0.65rem; cursor: pointer; display: none; }
.brand { font-weight: 700; }
.topnav { display: flex; gap: 1rem; margin-left: auto; }
.topnav a { color: #93c5fd; text-decoration: none; }
.layout { display: grid; grid-template-columns: 170px 1fr; min-height: 180px; position: relative; }
.sidebar { background: #dbeafe; padding: 1rem; transition: transform 0.2s; }
.sidebar a { display: block; color: #1e40af; text-decoration: none; margin-bottom: 0.5rem; }
main { padding: 1.25rem; }
.site-footer { background: #f1f5f9; color: #64748b; padding: 0.75rem 1rem; font-size: 0.85rem; }
@media (max-width: 560px) {
  .menu-btn { display: inline-block; }
  .layout { grid-template-columns: 1fr; }
  .sidebar { position: absolute; left: 0; top: 0; width: 180px; height: 100%; z-index: 5; transform: translateX(-100%); box-shadow: 2px 0 12px rgba(30,41,59,0.15); }
  .sidebar.open { transform: translateX(0); }
}

